onClick:
{{
(async () => {
  const ctx = appsmith.store.delete_context;

  if (!ctx || !ctx.action) {
    showAlert("No hay una acción de eliminación activa.", "warning");
    return;
  }

  if (!inpDeletePassword.text) {
    showAlert("Ingresa la contraseña de eliminación.", "warning");
    return;
  }

  if (!taDeleteReason.text) {
    showAlert("Ingresa el motivo de eliminación.", "warning");
    return;
  }

  await qValidateDeletePassword.run();

  const ok = qValidateDeletePassword.data?.[0]?.ok === true;

  if (!ok) {
    showAlert("Contraseña incorrecta.", "error");
    return;
  }

  if (ctx.action === "DELETE_CV_ITEM") {
    if (!ctx.item_no) {
      showAlert("No se identificó el ítem a eliminar.", "warning");
      return;
    }

    let items = appsmith.store.cv_items_proforma || [];
    const beforeCount = items.length;

    items = items
      .filter((x) => Number(x.item_no) !== Number(ctx.item_no))
      .map((x, i) => ({
        ...x,
        item_no: i + 1
      }));

    if (items.length === beforeCount) {
      showAlert("No se encontró el ítem en memoria.", "warning");
      return;
    }

    await storeValue("cv_items_proforma", items);
    await storeValue("cv_has_pending_changes", true);

    await JS_CvForm.clearItemForm();

    closeModal("mdlConfirmDelete");

    resetWidget("inpDeletePassword", true);
    resetWidget("taDeleteReason", true);
    resetWidget("tblCvDetalle", true);

    removeValue("delete_context");

    showAlert(
      "Ítem eliminado de la proforma temporal. Recuerda actualizar la proforma para persistir el cambio.",
      "success"
    );

    return;
  }

  if (ctx.action === "DELETE_CV_PROFORMA") {
    if (!ctx.id) {
      showAlert("No se identificó la proforma a eliminar.", "warning");
      return;
    }

    await bkCvDeleteProformaSoft.run();

    const result = bkCvDeleteProformaSoft.data?.[0] || {};

    await JS_CvForm.resetProformaForm();
    await storeValue("cv_has_pending_changes", false);

    await qCvProformasResumen.run();
    await qCvOperacionTotales.run();
    await qCvProformaCabecera.run();
    await qCvProformaDetalle.run();

    resetWidget("tblCvProformasResumen", true);
    resetWidget("tblCvDetalle", true);
    resetWidget("inpDeletePassword", true);
    resetWidget("taDeleteReason", true);

    closeModal("mdlConfirmDelete");
    removeValue("delete_context");

    showAlert(
      "Proforma eliminada correctamente. Cabecera: " +
        (result.proformas_eliminadas || 0) +
        " / Ítems: " +
        (result.items_eliminados || 0),
      "success"
    );

    return;
  }

  showAlert("Acción de eliminación no reconocida.", "error");
})();
}}
